import numpy as np
from leann.api import compute_embeddings

# Global cache dictionary
_cached_compute_memo = {}

def _cached_compute(cache_key: tuple, provider_options: Optional[Dict[str, Any]]):
    """Internal cached computation function."""
    texts_tuple, model_name, mode, options_set = cache_key
    texts_list = list(texts_tuple)

    # Reconstruct embedding_options from frozenset if needed
    embedding_opts = dict(options_set) if options_set else provider_options

    embeddings = compute_embeddings(
        chunks=texts_list,
        model_name=model_name,
        mode=mode,
        use_server=False,
        is_build=False,
        provider_options=embedding_opts
    )

    return np.asarray(embeddings)

def compute_embeddings_with_config(
    texts: List[str],
    model_name: str = "facebook/contriever",
    mode: str = "sentence-transformers",
    embedding_options: Optional[Dict[str, Any]] = None,
    use_cache: bool = False
) -> np.ndarray:
    """Compute embeddings with custom configuration and optional caching."""
    if not texts:
        raise ValueError("texts cannot be empty")

    valid_modes = {'sentence-transformers', 'mlx', 'openai', 'ollama'}
    if mode not in valid_modes:
        raise ValueError(f"mode must be one of {valid_modes}")

    # Handle embedding_options
    if embedding_options is None:
        embedding_options = {}
        options_set = None
    else:
        options_set = frozenset(embedding_options.items())

    # Determine provider_options
    if embedding_options and 'provider_options' in embedding_options:
        provider_options = embedding_options['provider_options']
    else:
        provider_options = embedding_options

    if use_cache:
        cache_key = (tuple(texts), model_name, mode, options_set)
        if cache_key in _cached_compute_memo:
            return _cached_compute_memo[cache_key]
        else:
            embeddings = _cached_compute(cache_key, provider_options)
            _cached_compute_memo[cache_key] = embeddings
            return embeddings
    else:
        embeddings = compute_embeddings(
            chunks=texts,
            model_name=model_name,
            mode=mode,
            use_server=False,
            is_build=False,
            provider_options=provider_options
        )
        return np.asarray(embeddings)

