def build_index_from_json_documents(
    json_file_path: str,
    index_path: str,
    text_field: str = "text",
    metadata_fields: Optional[List[str]] = None,
    backend_name: str = "hnsw"
) -> str:
    """Build a LEANN index from a JSON file containing documents."""
    # Check if JSON file exists
    if not Path(json_file_path).exists():
        raise FileNotFoundError(f"JSON file not found: {json_file_path}")

    try:
        with open(json_file_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
    except json.JSONDecodeError:
        raise ValueError("missing required field")

    # Check if data is a list
    if not isinstance(data, list):
        raise ValueError("missing required field")

    # Process documents
    documents = []
    for i, document in enumerate(data):
        # Check if document is a dictionary
        if not isinstance(document, dict):
            raise ValueError("missing required field")

        # Check if text_field exists
        if text_field not in document:
            raise ValueError("missing required field")

        text_content = document[text_field]

        # Prepare metadata
        if metadata_fields is None:
            # Include all fields except text_field
            metadata = {k: v for k, v in document.items() if k != text_field}
        else:
            # Include only specified metadata fields
            metadata = {field: document[field] for field in metadata_fields if field in document}

        # Create document dictionary for LEANN
        doc_dict = {
            'text': text_content,
            'metadata': metadata
        }
        documents.append(doc_dict)

    # Build index
    builder = LeannBuilder(backend_name=backend_name)
    for doc in documents:
        builder.add_text(doc['text'], metadata=doc['metadata'])

    # Save index
    builder.build_index(index_path)

    return index_path

