from collections import Counter, defaultdict

def get_index_statistics(index_path: str) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index."""
    index_dir = Path(index_path).parent
    if not index_dir.exists():
        raise FileNotFoundError(f"Index directory {index_dir} does not exist")

    try:
        searcher = LeannSearcher(index_path)
        pm = searcher.passage_manager
        passages = pm.get_all()

        total_passages = len(passages)
        metadata_fields = set()
        field_value_counts = defaultdict(Counter)

        for passage in passages:
            metadata = passage.metadata
            metadata_fields.update(metadata.keys())
            for field_name, value in metadata.items():
                field_value_counts[field_name][value] += 1

        return {
            "total_passages": total_passages,
            "metadata_fields": sorted(list(metadata_fields)),
            "field_value_counts": dict(field_value_counts)
        }
    except Exception as e:
        if "No such file" in str(e) or "not found" in str(e):
            raise FileNotFoundError(f"Index metadata file not found: {e}")
        raise

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields."""
    index_dir = Path(index_path).parent
    if not index_dir.exists():
        raise FileNotFoundError(f"Index directory {index_path} does not exist")

    try:
        searcher = LeannSearcher(index_path)
        pm = searcher.passage_manager
        passages = pm.get_all()

        total_passages = len(passages)
        if total_passages == 0:
            return {
                "coverage_percentage": 0.0,
                "field_coverage": {field: 0.0 for field in required_fields},
                "missing_fields": required_fields.copy()
            }

        covered_passages = 0
        field_counts = defaultdict(int)

        for passage in passages:
            metadata = passage.metadata
            has_all_fields = True

            for field in required_fields:
                if field in metadata:
                    field_counts[field] += 1
                else:
                    has_all_fields = False
                    break

            if has_all_fields:
                covered_passages += 1

        coverage_percentage = (covered_passages / total_passages) * 100

        field_coverage = {}
        missing_fields = []

        for field in required_fields:
            if field_counts[field] == 0:
                missing_fields.append(field)
            else:
                field_coverage[field] = round((field_counts[field] / total_passages) * 100, 2)

        return {
            "coverage_percentage": round(coverage_percentage, 2),
            "field_coverage": field_coverage,
            "missing_fields": missing_fields
        }
    except Exception as e:
        if "No such file" in str(e) or "not found" in str(e):
            raise FileNotFoundError(f"Index metadata file not found: {e}")
        raise

