def export_index_metadata(
    index_path: str,
    output_file: str
) -> Dict[str, Any]:
    """Export index metadata and passage information to a JSON file."""
    index_path_obj = Path(index_path)
    if not index_path_obj.exists():
        raise FileNotFoundError(f"Index metadata file not found at {index_path}")

    try:
        # Load the existing index
        builder = LeannBuilder.load_index(index_path)
        passage_manager = builder.passage_manager

        # Extract passages and metadata
        passages = passage_manager.get_all()  # Assuming this returns list of passage objects
        passage_dicts = []
        for passage in passages:
            passage_dicts.append({
                'id': passage.id,
                'text': passage.text,
                'metadata': passage.metadata if hasattr(passage, 'metadata') else {}
            })

        metadata = {
            'backend_name': builder.backend_name,
            'dimensions': builder.dimensions,
            'embedding_model': builder.embedding_model,
            'passage_sources': builder.config.get('passage_sources', []),
            'passages': passage_dicts,
            'version': builder.version
        }

        # Save to JSON
        with open(output_file, 'w', encoding='utf-8') as f:
            json.dump(metadata, f, indent=2)

        return {
            'exported_passages': len(passages),
            'output_file': output_file,
            'status': 'success'
        }

    except Exception as e:
        return {
            'exported_passages': 0,
            'output_file': output_file,
            'status': 'failed',
            'error': str(e)
        }

def import_index_from_metadata(
    export_file: str,
    index_path: str,
    backend_name: str = 'hnsw'
) -> Dict[str, Any]:
    """Import and rebuild an index from exported metadata and passages."""
    export_file_obj = Path(export_file)
    if not export_file_obj.exists():
        raise FileNotFoundError(f"Export file not found at {export_file}")

    try:
        # Load the exported data
        with open(export_file, 'r', encoding='utf-8') as f:
            data = json.load(f)

        # Validate required fields
        required_fields = ['backend_name', 'dimensions', 'embedding_model', 'passages']
        for field in required_fields:
            if field not in data:
                raise ValueError(f"Missing required field: {field}")

        if not isinstance(data['passages'], list):
            raise ValueError("Passages should be a list")

        # Initialize builder
        builder = LeannBuilder(
            backend_name=backend_name if backend_name else data['backend_name'],
            dimensions=data['dimensions'],
            embedding_model=data['embedding_model']
        )

        # Add passages
        for passage in data['passages']:
            if not isinstance(passage, dict) or 'text' not in passage:
                continue  # Skip invalid passages
            builder.add_text(
                passage['text'],
                passage_id=passage.get('id'),
                metadata=passage.get('metadata', {})
            )

        # Build index
        builder.build_index(index_path)

        return {
            'index_path': index_path,
            'passages_imported': len(data['passages']),
            'status': 'success'
        }

    except json.JSONDecodeError:
        raise ValueError("Invalid JSON format in export file")
    except Exception as e:
        return {
            'index_path': index_path,
            'passages_imported': 0,
            'status': 'failed',
            'error': str(e)
        }

from typing import List, Dict, Any
from leann.api import LeannBuilder
from pathlib import Path

def build_index_with_metadata_template(
    documents: List[Dict[str, Any]],
    index_path: str,
    metadata_template: Dict[str, Any] = None,
    backend_name: str = "hnsw"
) -> str:
    """Build a LEANN index and apply a metadata template to all documents."""
    if not documents:
        raise ValueError("documents list cannot be empty")

    processed_docs = []
    for doc in documents:
        processed_doc = doc.copy()

        if metadata_template is not None:
            if 'metadata' in doc:
                processed_doc['metadata'] = {**metadata_template, **doc['metadata']}
            else:
                processed_doc['metadata'] = metadata_template.copy()
        else:
            # Preserve original metadata if present
            if 'metadata' in doc:
                processed_doc['metadata'] = doc['metadata']

        processed_docs.append(processed_doc)

    builder = LeannBuilder(backend_name=backend_name)
    for doc in processed_docs:
        builder.add_text(doc['text'], metadata=doc.get('metadata', {}))

    index_path_obj = Path(index_path)
    builder.build_index(str(index_path_obj))

    return str(index_path_obj)

from typing import List, Dict, Any
from leann.api import LeannSearcher, SearchResult

def search_and_extract_field_values(
    index_path: str,
    query: str,
    extract_field: str,
    top_k: int = 10
) -> List[Any]:
    """Search in an index and extract unique values of a metadata field from results."""
    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"Index file not found: {index_path}")

    results = searcher.search(query, top_k=top_k)

    values = []
    for result in results:
        if extract_field in result.metadata:
            values.append(result.metadata[extract_field])

    # Remove duplicates while preserving order
    seen = set()
    unique_values = []
    for value in values:
        if value not in seen:
            seen.add(value)
            unique_values.append(value)

    return unique_values

